{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/IndentationRuleClassBodyTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class IndentationRuleClassBodyTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Issue - Given a class with multiline super type list without explicit constructor keyword`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - Given a class with explicit constructor and multiline super type list`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                // body
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - Given a class with annotation before explicit constructor and super type list`() {
        val code =
            """
            class Foo
                @Bar1 @Bar2
                constructor(
                    foo1: Foo1,
                    foo2: Foo2,
                ) : Foobar(
                    "foobar1",
                    "foobar2",
                ) {
                fun foo() = "foo"
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Issue - Given a class with annotation before explicit constructor without super type list`() {
        val code =
            """
            class Foo
                @Bar1 @Bar2
                constructor(
                    foo1: Foo1,
                    foo2: Foo2,
                ) {
                fun foo() = "foo"
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}
"}

