        // Inner indent contexts in reversed order
        var nextToAstNode: ASTNode = node.lastChildLeafOrSelf()
        node
            .findChildByType(WHERE_KEYWORD)
            ?.let { where ->
                val typeConstraintList =
                    requireNotNull(
                        where.nextCodeSibling(),
                    ) { "Can not find code sibling after WHERE in CLASS" }
                require(
                    typeConstraintList.elementType == TYPE_CONSTRAINT_LIST,
                ) { "Code sibling after WHERE in CLASS is not a TYPE_CONSTRAINT_LIST" }
                nextToAstNode =
                    startIndentContext(
                        fromAstNode = where.getPrecedingLeadingCommentsAndWhitespaces(),
                        toAstNode = typeConstraintList.lastChildLeafOrSelf(),
                    ).prevCodeLeaf()
            }

        val primaryConstructor = node.findChildByType(PRIMARY_CONSTRUCTOR)
        if (codeStyle == ktlint_official && primaryConstructor.hasConstructorKeywordPrecededByNewline()) {
            // Indent the constructor and super type list but not the class body
            val superTypeList = node.findChildByType(SUPER_TYPE_LIST)
            val toAstNode =
                superTypeList?.lastChildLeafOrSelf()
                    ?: primaryConstructor!!.lastChildLeafOrSelf()
            nextToAstNode =
                startIndentContext(
                    fromAstNode = primaryConstructor!!.getPrecedingLeadingCommentsAndWhitespaces(),
                    toAstNode = toAstNode,
                ).prevCodeLeaf()
        } else {
            node
                .findChildByType(SUPER_TYPE_LIST)
                ?.let { superTypeList ->
                    nextToAstNode =
                        startIndentContext(
                            fromAstNode = superTypeList.getPrecedingLeadingCommentsAndWhitespaces(),
                            toAstNode = superTypeList.lastChildLeafOrSelf(),
                        ).prevCodeLeaf()
                }
        }

        // Leading annotations and comments should be indented at same level as class itself
        startIndentContext(
            fromAstNode = node,
            toAstNode = nextToAstNode,
            childIndent = "",
        )
    }

    private fun ASTNode?.hasConstructorKeywordPrecededByNewline(): Boolean {
        this ?: return false
        val constructorKeyword = findChildByType(CONSTRUCTOR_KEYWORD) ?: return false
        // Constructor keyword is preceded by a newline if there's whitespace with newline before the modifier list
        // or before the constructor keyword itself
        return constructorKeyword
            .prevLeaf { !it.isWhiteSpace() && !it.isPartOfComment() }
            ?.nextLeaf()
            ?.isWhiteSpaceWithNewline() == true
    }"}

